const startDate = new Date(items[0]?.json["Start date"]);
const endDate = new Date(items[0]?.json["End date"]);
const dateChunks = [];

while (startDate < endDate) {
  const chunkEnd = new Date(startDate);
  chunkEnd.setDate(chunkEnd.getDate() + 4);
  if (chunkEnd > endDate) {
    chunkEnd.setDate(endDate.getDate());
  }

  dateChunks.push({
    start: startDate.toISOString().split("T")[0],
    end: chunkEnd.toISOString().split("T")[0],
  });

  startDate.setDate(startDate.getDate() + 5);
}

return dateChunks.map((chunk, index) => ({ json: chunk, pairedItem: index }));

// n8n Code node: aggregate tracked time by user/project
// Input options supported:
//  1) items[0].json.data = [ { userName, trackedTime, projectName }, ... ]
//  2) items = [ { json: { userName, trackedTime, projectName } }, ... ]

const round2 = (n) => Math.round((Number(n) + Number.EPSILON) * 100) / 100;

// Normalize input to a flat array of records
let records = [];
if (Array.isArray(items?.[0]?.json?.data)) {
  records = items[0].json.data;
} else if (Array.isArray(items) && items.length > 0 && items[0]?.json) {
  // Treat each incoming item as a record
  records = items.map(i => i.json);
}

// Handle empty input gracefully
if (!Array.isArray(records) || records.length === 0) {
  return [
    {
      json: {
        generatedAt: new Date().toISOString(),
        summary: { totalUsers: 0, totalTrackedTime: 0 },
        users: []
      }
    }
  ];
}

// Aggregate per user and per project
const usersMap = new Map(); // userName -> { total: number, projects: Map(projectName -> time) }

for (const r of records) {
  const userName = (r.userName ?? "").trim();
  const projectName = (r.projectName ?? "").trim();
  const tracked = Number(r.trackedTime) || 0;
  if (!userName) continue;

  if (!usersMap.has(userName)) {
    usersMap.set(userName, { total: 0, projects: new Map() });
  }
  const u = usersMap.get(userName);
  u.total += tracked;

  if (projectName) {
    u.projects.set(projectName, (u.projects.get(projectName) || 0) + tracked);
  }
}

// Build users array with rounding and fractions
const users = [];
let grandTotal = 0;

for (const [userName, data] of usersMap) {
  const totalTime = round2(data.total);
  grandTotal += totalTime;

  const projects = Array.from(data.projects.entries())
    .map(([projectName, time]) => {
      const t = round2(time);
      const fraction = totalTime > 0 ? round2(t / totalTime) : 0; // 0–1 fraction
      return { projectName, time: t, percentOfUserTotal: fraction };
    })
    .sort((a, b) => (b.time - a.time) || a.projectName.localeCompare(b.projectName));

  users.push({ userName, totalTime, projects });
}

// Sort users (predictable output)
users.sort((a, b) => a.userName.localeCompare(b.userName));

// Wrap exactly as required by you and n8n
return [
  {
    json: {
      generatedAt: new Date().toISOString(),
      summary: {
        totalUsers: users.length,
        totalTrackedTime: round2(grandTotal)
      },
      users
    }
  }
];

